/**
 * ============================================================================
 *  WARNING — THIS FILE IS SOURCE-CONTROLLED (spiralpalooza git repo)
 *
 *  DO NOT EDIT this file until you have read the "Working on the Apps Script
 *  backends with clasp" section of the repo's README.md. Editing the live
 *  version directly can drift from, or be overwritten by, the git copy.
 * ============================================================================
 *
 * Spiralpalooza RSVP — Apps Script backend (container-bound to the RSVPs sheet).
 *
 * Endpoints:
 *   doPost  — append a new RSVP, or update an existing one by edit token
 *   doGet   — ?edit=<token> returns one record for the edit form;
 *             otherwise returns the public "Who's Coming" list
 *
 * Sheet headers (row 1, any order — reads/writes are header-keyed):
 *   Timestamp | First Name | Last Name | Email | Phone | Mailing Address |
 *   Years at Children First | Attending | Role / Affiliation | Party Members |
 *   Total in Party | List Permission | Private Notes | Public Notes |
 *   Pizza GF | Pizza Vegan | Pizza GF+Vegan | Edit Token | Last Updated
 *
 * Script Properties (Project Settings -> Script Properties):
 *   MAILER_URL   — /exec URL of the shared mailer microservice
 *   MAIL_SECRET  — shared secret the mailer checks (same value as the mailer)
 */

// ---- Config ----------------------------------------------------------------

var RSVP_SHEET_NAME = 'RSVPs';

// Live site base URL, must end with '/'. Used to build the edit link in emails.
var SITE_URL = 'https://spiralpalooza.org/';

// Canonical header row, in order. ensureHeaders_ uses this to create the sheet or
// to backfill any missing columns (e.g. Edit Token / Last Updated on a sheet from
// before the edit-link feature). The tests also build their sheet from this.
var RSVP_HEADERS = [
  'Timestamp', 'First Name', 'Last Name', 'Email', 'Phone', 'Mailing Address',
  'Years at Children First', 'Attending', 'Role / Affiliation', 'Party Members',
  'Total in Party', 'List Permission', 'Private Notes', 'Public Notes',
  'Pizza GF', 'Pizza Vegan', 'Pizza GF+Vegan', 'Edit Token', 'Last Updated'
];

// ---- Write path (doPost) ---------------------------------------------------

function doPost(e) {
  try {
    var data = JSON.parse(e.postData.contents);

    // Reject incomplete submissions before touching the sheet or sending mail.
    // This is data-integrity validation, NOT access control — the endpoint is public.
    var problem = validateRsvp_(data);
    if (problem) {
      return ContentService
        .createTextOutput(JSON.stringify({ status: "error", message: problem }))
        .setMimeType(ContentService.MimeType.JSON);
    }

    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = ss.getSheetByName(RSVP_SHEET_NAME) || ss.insertSheet(RSVP_SHEET_NAME);
    ensureHeaders_(sheet);

    var saved = saveRsvp_(sheet, data);

    sendEmail_(data, saved.token, saved.isUpdate);

    return ContentService
      .createTextOutput(JSON.stringify({ status: "success" }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    console.error('doPost failed: ' + (err && err.stack ? err.stack : err));
    return ContentService
      .createTextOutput(JSON.stringify({ status: "error", message: err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

// Maps an incoming RSVP payload to sheet columns by header text. Timestamp,
// Edit Token, and Last Updated are managed by doPost / updateRowByToken_.
function rsvpRow_(data) {
  return {
    'First Name':              data.firstName,
    'Last Name':               data.lastName,
    'Email':                   data.email,
    'Phone':                   data.phone,
    'Mailing Address':         data.address,
    'Years at Children First': data.years,
    'Attending':               data.attending || 'Yes',
    'Role / Affiliation':      data.role,
    'Party Members':           data.partyMembers,
    'Total in Party':          data.totalInParty,
    'List Permission':         data.listPermission,
    'Private Notes':           data.notesPrivate,
    'Public Notes':            data.notesPublic,
    'Pizza GF':                data.pizzaGF || 0,
    'Pizza Vegan':             data.pizzaVegan || 0,
    'Pizza GF+Vegan':          data.pizzaGFVegan || 0
  };
}

// Writes the RSVP to the sheet: updates the row matching data.editToken if found,
// otherwise appends a new row with a fresh token. Returns { token, isUpdate }.
// No email/validation here — kept separate from doPost so the write path can be
// tested without going through the email code path.
function saveRsvp_(sheet, data) {
  var values = rsvpRow_(data);

  if (data.editToken) {
    values['Last Updated'] = new Date();
    if (updateRowByToken_(sheet, data.editToken, values)) {
      return { token: data.editToken, isUpdate: true };
    }
  }
  var token = Utilities.getUuid();      // new RSVP, or editToken not found (falls back to new)
  values['Timestamp'] = new Date();
  values['Edit Token'] = token;
  appendByHeader_(sheet, values);
  return { token: token, isUpdate: false };
}

// Validates the genuinely required RSVP fields for data integrity (NOT access
// control — the endpoint is public; this just keeps junk/incomplete rows out).
// Returns an error message string, or '' if the payload is acceptable.
function validateRsvp_(data) {
  if (!data) return 'Missing request body.';
  if (!String(data.firstName || '').trim()) return 'First name is required.';
  if (!String(data.lastName  || '').trim()) return 'Last name is required.';
  var email = String(data.email || '').trim();
  if (!email || email.indexOf('@') === -1)  return 'A valid email is required.';
  if (!String(data.years || '').trim())     return 'Years at Children First is required.';
  return '';
}

// Create the sheet's header row if it's empty, or backfill any missing headers
// (Edit Token / Last Updated may not exist on a sheet from before the edit-link
// feature). Existing columns and their order are left untouched; new headers are
// appended at the end, and existing data rows just get blank cells under them.
function ensureHeaders_(sheet) {
  if (sheet.getLastRow() === 0) {
    sheet.appendRow(RSVP_HEADERS);
    sheet.getRange(1, 1, 1, RSVP_HEADERS.length).setFontWeight('bold');
    sheet.setFrozenRows(1);
    return;
  }
  // getLastColumn() is the widest used column across the whole sheet, so a data
  // row wider than the header row would pad row 1 with trailing blanks. Trim those
  // so missing headers append right after the real ones, not after empty gap columns.
  var rowOne = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]
    .map(function (h) { return String(h).trim(); });
  var width = rowOne.length;
  while (width > 0 && rowOne[width - 1] === '') width--;
  var headers = rowOne.slice(0, width);
  var missing = RSVP_HEADERS.filter(function (h) { return headers.indexOf(h) === -1; });
  if (missing.length) {
    var start = width + 1;
    sheet.getRange(1, start, 1, missing.length).setValues([missing]).setFontWeight('bold');
  }
}

// Append a row by matching the values object's keys to the sheet's header row.
// Column order in the sheet does not have to match code order: a header with no
// matching key is left blank, and a key with no matching header is ignored.
function appendByHeader_(sheet, values) {
  var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  var row = headers.map(function (h) {
    var key = String(h).trim();
    return Object.prototype.hasOwnProperty.call(values, key) ? values[key] : '';
  });
  sheet.appendRow(row);
}

// Finds the row whose 'Edit Token' matches and overwrites it. Columns not present
// in `values` (Timestamp, Edit Token) keep their existing cell. Returns false if
// no row matches, so doPost can fall back to appending a new row.
function updateRowByToken_(sheet, token, values) {
  var grid = sheet.getDataRange().getValues();
  var headers = grid[0];
  var tokenCol = headers.indexOf('Edit Token');
  if (tokenCol === -1) return false;

  for (var i = 1; i < grid.length; i++) {
    if (String(grid[i][tokenCol]) === String(token)) {
      var row = headers.map(function (h, c) {
        var key = String(h).trim();
        return Object.prototype.hasOwnProperty.call(values, key) ? values[key] : grid[i][c];
      });
      sheet.getRange(i + 1, 1, 1, row.length).setValues([row]);
      return true;
    }
  }
  return false;
}

// ---- Read path (doGet) -----------------------------------------------------

function doGet(e) {
  if (e && e.parameter && e.parameter.edit) {
    return getRsvpForEdit_(e.parameter.edit);
  }

  try {
    var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(RSVP_SHEET_NAME);

    if (!sheet || sheet.getLastRow() <= 1) {
      return ContentService
        .createTextOutput(JSON.stringify({ status: "success", rsvps: [], grouped: [] }))
        .setMimeType(ContentService.MimeType.JSON);
    }

    var rows = sheet.getDataRange().getValues();
    var headers = rows.shift();
    var col = {};
    headers.forEach(function (h, i) { col[String(h).trim()] = i; });

    var rsvps   = [];  // flat: host + each party member as its own entry
    var grouped = [];  // nested: one entry per host, party members in a "party" array

    rows.forEach(function (r) {
      // Skip anyone who said they can't attend.
      if (String(r[col['Attending']]).trim().toLowerCase() === 'no') return;
      // Only list people who gave permission.
      if (String(r[col['List Permission']]).trim().toLowerCase() !== 'yes') return;

      var hostName = (String(r[col['First Name']] || '').trim() + ' ' +
                      String(r[col['Last Name']]  || '').trim()).trim();
      if (!hostName) return;

      var years = (r[col['Years at Children First']] || '').toString().trim();
      var note  = (r[col['Public Notes']] || '').toString().trim();

      // Party members are stored as "Name (rel) [email]"; strip both the bracketed
      // email and the parenthetical relationship so the public list shows names only.
      var party = String(r[col['Party Members']] || '')
        .split(/\s*\|\s*/)
        .map(function (m) {
          return m.replace(/\s*\[[^\]]*\]\s*/g, '').replace(/\s*\([^)]*\)\s*/g, '').trim();
        })
        .filter(function (m) { return m; });

      rsvps.push({ name: hostName, years: years, note: note });
      party.forEach(function (m) { rsvps.push({ name: m, years: years }); });

      grouped.push({ name: hostName, years: years, note: note, party: party });
    });

    rsvps.sort(function (a, b) { return a.name.localeCompare(b.name); });
    grouped.sort(function (a, b) { return a.name.localeCompare(b.name); });

    return ContentService
      .createTextOutput(JSON.stringify({ status: "success", rsvps: rsvps, grouped: grouped }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService
      .createTextOutput(JSON.stringify({ status: "error", message: err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

// Returns one record by edit token, shaped for the edit form: {found, record}.
function getRsvpForEdit_(token) {
  try {
    var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(RSVP_SHEET_NAME);
    var grid = sheet.getDataRange().getValues();
    var headers = grid[0];
    var col = {};
    headers.forEach(function (h, i) { col[String(h).trim()] = i; });
    var tokenCol = col['Edit Token'];

    var result = { found: false };
    if (tokenCol != null) {
      for (var i = 1; i < grid.length; i++) {
        if (String(grid[i][tokenCol]) === String(token)) {
          var r = grid[i];
          var get = function (name) { return col[name] != null ? r[col[name]] : ''; };
          result = {
            found: true,
            record: {
              firstName:      get('First Name'),
              lastName:       get('Last Name'),
              email:          get('Email'),
              phone:          get('Phone'),
              address:        get('Mailing Address'),
              years:          get('Years at Children First'),
              attending:      get('Attending') || 'Yes',
              role:           get('Role / Affiliation'),
              party:          parseParty_(get('Party Members')),
              pizzaGF:        get('Pizza GF') || 0,
              pizzaVegan:     get('Pizza Vegan') || 0,
              pizzaGFVegan:   get('Pizza GF+Vegan') || 0,
              notesPrivate:   get('Private Notes'),
              notesPublic:    get('Public Notes'),
              listPermission: get('List Permission') || 'No'
            }
          };
          break;
        }
      }
    }
    return ContentService
      .createTextOutput(JSON.stringify(result))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    console.error('getRsvpForEdit_ failed: ' + err);
    return ContentService
      .createTextOutput(JSON.stringify({ found: false, error: err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

// "Name (rel) [email] | Name2 (rel2)" -> [{name, rel, email}, ...]
// Assumes names/relationships don't themselves contain "|", "(", ")", "[", or "]"
// (the frontend's serialization format); such characters will misparse. Acceptable
// for this audience — revisit (e.g. store JSON) if that constraint ever bites.
function parseParty_(s) {
  return String(s || '').split(/\s*\|\s*/).filter(function (m) { return m.trim(); }).map(function (m) {
    var email = '', rel = '';
    var em = m.match(/\[([^\]]*)\]/); if (em) { email = em[1]; m = m.replace(em[0], ''); }
    var rm = m.match(/\(([^)]*)\)/);  if (rm) { rel   = rm[1]; m = m.replace(rm[0], ''); }
    return { name: m.trim(), rel: rel.trim(), email: email.trim() };
  });
}

// ---- Email -----------------------------------------------------------------

// Build and send the RSVP confirmation. Best-effort: sendConfirmation_ swallows
// failures, and we bail early if there's no usable email address.
function sendEmail_(data, token, isUpdate) {
  if (!data.email || data.email.indexOf('@') === -1) return;
  var base = pickSiteBase_(data.siteUrl);
  var sep = base.indexOf('?') === -1 ? '?' : '&';
  var editUrl = token ? (base + sep + 'edit=' + token + '&type=rsvp') : '';
  sendConfirmation_(data.email, 'Your Spiralpalooza RSVP', genEmailHTML_(data, editUrl, isUpdate));
}

// Builds the edit-link base from the URL the form was served from (data.siteUrl),
// so links work across local/preview/production without code changes. The caller's
// URL is only trusted if its host is on the allowlist — otherwise we fall back to
// the configured SITE_URL, to avoid becoming a phishing/open-redirect vector (the
// link lands in an email, so an attacker-controlled URL could not be allowed through).
function pickSiteBase_(clientUrl) {
  if (clientUrl && /^https?:\/\//i.test(clientUrl)) {
    // Match on the URL's HOST, not a substring — a substring check would also let
    // "https://evil.com/?x=localhost" or "https://localhost.attacker.com/" through.
    var m = clientUrl.match(/^https?:\/\/([^\/?#]+)/i);
    var host = m ? m[1].split(':')[0].toLowerCase() : '';
    if (host === 'localhost' || host === '127.0.0.1' ||
        host === 'spiralpalooza.org' || host.endsWith('.spiralpalooza.org') ||
        host === 'spiralpalooza.pages.dev' || host.endsWith('.spiralpalooza.pages.dev')) {
      return clientUrl;
    }
  }
  return SITE_URL;
}

// Generate the email HTML. Factored out to make this testable without sending email.
function genEmailHTML_(data, editUrl, isUpdate) {
  var heading = isUpdate ? 'Your RSVP has been updated' : 'Your RSVP is in. Thank you!';
  var editLine = editUrl
    ? '<p style="color:#7A4010;font-size:13px">Need to change anything? Use your personal link to update your RSVP:<br><a href="' + editUrl + '">' + editUrl + '</a></p>'
    : '';

  // Regret
  if (data.attending === 'No') {
    return [
      '<div style="font-family:Arial,sans-serif;color:#3D1C00;line-height:1.6">',
        '<h2 style="color:#7B3A0E">' + heading + '</h2>',
        '<p>Hi ' + esc_(data.firstName) + ',</p>',
        '<p>Thanks for letting us know you can\'t make it to ' +
          'Spiralpalooza on Saturday, October 3, 2026. We\'ll miss you!</p>',
        (data.notesPublic ? '<p><strong>Your message:</strong> ' + esc_(data.notesPublic) + '</p>' : ''),
        '<p>If your plans change, you can update your RSVP using the link below.</p>',
        editLine,
      '</div>'
    ].join('');
  }

  // Attending
  var members = (data.partyMembers || '').split(/\s*\|\s*/).filter(function (m) { return m.trim(); });
  var partyHtml = members.length
    ? '<ul>' + members.map(function (m) { return '<li>' + esc_(m) + '</li>'; }).join('') + '</ul>'
    : '<p>(just you, for now)</p>';

  // Special-order pizza counts — only show the ones that are non-zero.
  var pizzaParts = [];
  if (data.pizzaGF)      pizzaParts.push(esc_(data.pizzaGF) + ' gluten-free');
  if (data.pizzaVegan)   pizzaParts.push(esc_(data.pizzaVegan) + ' vegan');
  if (data.pizzaGFVegan) pizzaParts.push(esc_(data.pizzaGFVegan) + ' gluten-free + vegan');
  var pizzaHtml = pizzaParts.length
    ? '<p><strong>Special-order pizza:</strong> ' + pizzaParts.join(', ') + '</p>'
    : '';

  return [
    '<div style="font-family:Arial,sans-serif;color:#3D1C00;line-height:1.6">',
      '<h2 style="color:#7B3A0E">' + heading + '</h2>',
      '<p>Hi ' + esc_(data.firstName) + ',</p>',
      '<p>We can\'t wait to see you at Spiralpalooza on ' +
        '<strong>Saturday, October 3, 2026</strong> at the Children First Playground, ' +
        '1211 Carroll St, Durham, NC.</p>',
      '<p><strong>Here\'s what you told us:</strong></p>',
      '<ul>',
        '<li><strong>Name:</strong> ' + esc_(data.firstName) + ' ' + esc_(data.lastName) + '</li>',
        '<li><strong>Years with Children First:</strong> ' + esc_(data.years) + '</li>',
        (data.role ? '<li><strong>CF Affiliation:</strong> ' + esc_(data.role) + '</li>' : ''),
      '</ul>',
      '<p><strong>Your party:</strong></p>',
      partyHtml,
      pizzaHtml,
      (data.notesPublic ? '<p><strong>Your public note:</strong> ' + esc_(data.notesPublic) + '</p>' : ''),
      (data.notesPrivate ? '<p><strong>Your private note (only the organizers see this):</strong> ' + esc_(data.notesPrivate) + '</p>' : ''),
      editLine,
    '</div>'
  ].join('');
}

// Best-effort confirmation send. Calls the mailer microservice server-to-server
// so the email goes out from childrenfirstmail, not from this script's owner.
// Never throws — a mail hiccup must not fail the RSVP/order/volunteer write.
// A copy of this goes in each script.
function sendConfirmation_(to, subject, htmlBody) {
  try {
    var props = PropertiesService.getScriptProperties();
    var url = props.getProperty('MAILER_URL');
    var secret = props.getProperty('MAIL_SECRET');
    if (!url || !secret || !to) return;

    UrlFetchApp.fetch(url, {
      method: 'post',
      contentType: 'application/json',
      muteHttpExceptions: true,
      payload: JSON.stringify({ secret: secret, to: to, subject: subject, htmlBody: htmlBody })
    });
  } catch (err) {
    // swallow — confirmation email is non-critical
  }
}

// Escape user-supplied text before dropping it into HTML.
function esc_(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

