// ---- Test config -----------------------------------------------------------

var TEST_SHEET_NAME = 'RSVP_TEST';

// RSVP_HEADERS (the production header row the tests build their sheet from) now
// lives in the Config section at the top, since ensureHeaders_ uses it too.

// ---- Tiny assert + sheet helpers -------------------------------------------

function assertEquals_(label, expected, actual) {
  // String() so 0 and "0", or '' and a blank cell, compare equal.
  if (String(expected) !== String(actual)) {
    throw new Error('FAIL ' + label + ': expected "' + expected + '" but got "' + actual + '"');
  }
  Logger.log('  PASS ' + label);
}

function assertTruthy_(label, actual) {
  if (!actual) throw new Error('FAIL ' + label + ': expected a value but got "' + actual + '"');
  Logger.log('  PASS ' + label);
}

// Build a fresh test sheet with the given headers (defaults to production order).
function makeTestSheet_(headers) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var existing = ss.getSheetByName(TEST_SHEET_NAME);
  if (existing) ss.deleteSheet(existing);
  var sheet = ss.insertSheet(TEST_SHEET_NAME);
  sheet.appendRow(headers || RSVP_HEADERS);
  return sheet;
}

// Read the most recently appended row back as a {header: value} object.
function lastRowAsObject_(sheet) {
  var values = sheet.getDataRange().getValues();
  var headers = values[0];
  var last = values[values.length - 1];
  var obj = {};
  headers.forEach(function (h, i) { obj[String(h).trim()] = last[i]; });
  return obj;
}

function cleanupTestSheet_() {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName(TEST_SHEET_NAME);
  if (sheet) ss.deleteSheet(sheet);
}

// ---- Sample payloads --------------------------------------------------------

function fullPayload_() {
  return {
    firstName: 'Ada', lastName: 'Lovelace', email: 'chloe.palenchar@gmail.com',
    phone: '919-555-0100', address: '1 Analytical Way, Durham NC',
    years: '1994-2001', attending: 'Yes', role: 'Parent, Teacher / Staff',
    partyMembers: 'Sam (spouse) [sam@example.com] | Iris (kid)',
    totalInParty: 3, listPermission: 'Yes',
    notesPrivate: 'Arriving early to help.', notesPublic: 'So excited!',
    pizzaGF: 2, pizzaVegan: 1, pizzaGFVegan: 0
  };
}

// ---- Data-path tests --------------------------------------------------------

function testFullPayload_() {
  Logger.log('testFullPayload_');
  var sheet = makeTestSheet_();
  var data = fullPayload_();

  appendByHeader_(sheet, rsvpRow_(data));
  var row = lastRowAsObject_(sheet);

  assertEquals_('First Name', 'Ada', row['First Name']);
  assertEquals_('Last Name', 'Lovelace', row['Last Name']);
  assertEquals_('Email', 'chloe.palenchar@gmail.com', row['Email']);
  assertEquals_('Phone', '919-555-0100', row['Phone']);
  assertEquals_('Mailing Address', '1 Analytical Way, Durham NC', row['Mailing Address']);
  assertEquals_('Years at Children First', '1994-2001', row['Years at Children First']);
  assertEquals_('Attending', 'Yes', row['Attending']);
  assertEquals_('Role / Affiliation', 'Parent, Teacher / Staff', row['Role / Affiliation']);
  assertEquals_('Party Members', 'Sam (spouse) [sam@example.com] | Iris (kid)', row['Party Members']);
  assertEquals_('Total in Party', 3, row['Total in Party']);
  assertEquals_('List Permission', 'Yes', row['List Permission']);
  assertEquals_('Private Notes', 'Arriving early to help.', row['Private Notes']);
  assertEquals_('Public Notes', 'So excited!', row['Public Notes']);
  assertEquals_('Pizza GF', 2, row['Pizza GF']);
  assertEquals_('Pizza Vegan', 1, row['Pizza Vegan']);
  assertEquals_('Pizza GF+Vegan', 0, row['Pizza GF+Vegan']);
}

function testMissingOptionalFields_() {
  Logger.log('testMissingOptionalFields_');
  var sheet = makeTestSheet_();
  // Only the required fields; everything optional omitted.
  var data = {
    firstName: 'Grace', lastName: 'Hopper', email: 'grace@example.com',
    years: '1985', totalInParty: 1, listPermission: 'No'
  };

  appendByHeader_(sheet, rsvpRow_(data));
  var row = lastRowAsObject_(sheet);

  assertEquals_('First Name', 'Grace', row['First Name']);
  assertEquals_('Attending defaults Yes', 'Yes', row['Attending']);
  assertEquals_('Phone blank', '', row['Phone']);
  assertEquals_('Mailing Address blank', '', row['Mailing Address']);
  assertEquals_('Party Members blank', '', row['Party Members']);
  assertEquals_('Private Notes blank', '', row['Private Notes']);
  assertEquals_('Public Notes blank', '', row['Public Notes']);
  // Pizza counts default to 0 via `data.pizzaGF || 0`, even when absent.
  assertEquals_('Pizza GF defaults 0', 0, row['Pizza GF']);
  assertEquals_('Pizza Vegan defaults 0', 0, row['Pizza Vegan']);
  assertEquals_('Pizza GF+Vegan defaults 0', 0, row['Pizza GF+Vegan']);
}

function testColumnOrderIndependent_() {
  Logger.log('testColumnOrderIndependent_');
  // Same headers, deliberately scrambled order.
  var scrambled = RSVP_HEADERS.slice().reverse();
  var sheet = makeTestSheet_(scrambled);
  var data = fullPayload_();

  appendByHeader_(sheet, rsvpRow_(data));
  var row = lastRowAsObject_(sheet);

  // Values must still land under the right header names despite the reordering.
  assertEquals_('First Name (scrambled)', 'Ada', row['First Name']);
  assertEquals_('Pizza GF (scrambled)', 2, row['Pizza GF']);
  assertEquals_('List Permission (scrambled)', 'Yes', row['List Permission']);
  assertEquals_('Public Notes (scrambled)', 'So excited!', row['Public Notes']);
}

