// ---- doPost / edit-token / doGet tests -------------------------------------

function testDoPost_endToEnd_() {
  Logger.log('testDoPost_endToEnd_');
  var sheet = makeTestSheet_();

  // Point doPost at the test sheet for the duration of this test.
  var savedName = RSVP_SHEET_NAME;
  RSVP_SHEET_NAME = TEST_SHEET_NAME;
  try {
    var data = fullPayload_();
    var e = { postData: { contents: JSON.stringify(data) } };

    var res = doPost(e);
    var out = JSON.parse(res.getContent());
    assertEquals_('doPost returns success', 'success', out.status);

    var row = lastRowAsObject_(sheet);
    assertTruthy_('doPost stamped Timestamp', row['Timestamp']);
    assertTruthy_('doPost generated Edit Token', row['Edit Token']);
    assertEquals_('doPost wrote First Name', 'Ada', row['First Name']);
    assertEquals_('doPost wrote Pizza GF', 2, row['Pizza GF']);
    assertEquals_('doPost wrote List Permission', 'Yes', row['List Permission']);
  } finally {
    RSVP_SHEET_NAME = savedName;
  }
}

function testSaveRsvp_updateByToken_() {
  Logger.log('testSaveRsvp_updateByToken_');
  var sheet = makeTestSheet_();

  // First save creates a row + token (no email — saveRsvp_ is the write path only).
  var first = saveRsvp_(sheet, fullPayload_());
  assertTruthy_('token generated on new', first.token);
  assertEquals_('new save is not an update', false, first.isUpdate);

  // Save again with the token and a changed field.
  var upd = fullPayload_();
  upd.firstName = 'Augusta';
  upd.editToken = first.token;
  var second = saveRsvp_(sheet, upd);

  assertEquals_('update reuses token', first.token, second.token);
  assertEquals_('flagged as update', true, second.isUpdate);
  // Row updated in place, not appended (header + 1 data row = 2).
  assertEquals_('row count unchanged after update', 2, sheet.getLastRow());
  var row = lastRowAsObject_(sheet);
  assertEquals_('first name updated', 'Augusta', row['First Name']);
  assertEquals_('token preserved', first.token, row['Edit Token']);
  assertTruthy_('Last Updated stamped', row['Last Updated']);
}

function testGetRsvpForEdit_() {
  Logger.log('testGetRsvpForEdit_');
  var sheet = makeTestSheet_();
  var saved = saveRsvp_(sheet, fullPayload_());   // seed without sending email
  var savedName = RSVP_SHEET_NAME;
  RSVP_SHEET_NAME = TEST_SHEET_NAME;
  try {
    var out = JSON.parse(getRsvpForEdit_(saved.token).getContent());
    assertEquals_('found', true, out.found);
    assertEquals_('record first name', 'Ada', out.record.firstName);
    assertEquals_('record attending defaults Yes', 'Yes', out.record.attending);
    assertEquals_('party parsed count', 2, out.record.party.length);
    assertEquals_('party member name', 'Sam', out.record.party[0].name);
    assertEquals_('party member rel', 'spouse', out.record.party[0].rel);
    assertEquals_('party member email', 'sam@example.com', out.record.party[0].email);

    var miss = JSON.parse(getRsvpForEdit_('no-such-token').getContent());
    assertEquals_('unknown token not found', false, miss.found);
  } finally {
    RSVP_SHEET_NAME = savedName;
  }
}

