function testParseParty_() {
  Logger.log('testParseParty_');
  assertEquals_('empty string -> no members', 0, parseParty_('').length);

  var full = parseParty_('Sam (spouse) [sam@example.com]');
  assertEquals_('full member name', 'Sam', full[0].name);
  assertEquals_('full member rel', 'spouse', full[0].rel);
  assertEquals_('full member email', 'sam@example.com', full[0].email);

  var nameOnly = parseParty_('Iris');
  assertEquals_('name-only name', 'Iris', nameOnly[0].name);
  assertEquals_('name-only rel blank', '', nameOnly[0].rel);
  assertEquals_('name-only email blank', '', nameOnly[0].email);

  var relNoEmail = parseParty_('Pat (kid)');
  assertEquals_('rel-no-email rel', 'kid', relNoEmail[0].rel);
  assertEquals_('rel-no-email email blank', '', relNoEmail[0].email);

  var two = parseParty_('Sam (spouse) [sam@x.com] | Iris (kid)');
  assertEquals_('two members parsed', 2, two.length);
  assertEquals_('second member name', 'Iris', two[1].name);
}

