// ---- email html assert helpers ---------------------------------------------

function assertHas_(label, html, needle) {
  if (html.indexOf(needle) === -1) {
    throw new Error('FAIL ' + label + ': expected HTML to contain "' + needle + '"');
  }
  Logger.log('  PASS ' + label);
}

function assertLacks_(label, html, needle) {
  if (html.indexOf(needle) !== -1) {
    throw new Error('FAIL ' + label + ': expected HTML to NOT contain "' + needle + '"');
  }
  Logger.log('  PASS ' + label);
}

// ---- email html tests ------------------------------------------------------

function testEmail_fullPayload_() {
  Logger.log('testEmail_fullPayload_');
  var html = genEmailHTML_({
    firstName: 'Ada', lastName: 'Lovelace', years: '1994-2001',
    role: 'Parent', partyMembers: 'Sam (spouse) | Iris (kid)',
    pizzaGF: 2, pizzaVegan: 1, pizzaGFVegan: 0,
    notesPublic: 'So excited!', notesPrivate: 'Arriving early.'
  });

  assertHas_('name', html, 'Ada Lovelace');
  assertHas_('years', html, '1994-2001');
  assertHas_('role', html, 'CF Affiliation:</strong> Parent');
  assertHas_('party member Sam', html, '<li>Sam (spouse)</li>');
  assertHas_('party member Iris', html, '<li>Iris (kid)</li>');
  assertHas_('pizza gf', html, '2 gluten-free');
  assertHas_('pizza vegan', html, '1 vegan');
  assertLacks_('no gf+vegan (was 0)', html, 'gluten-free + vegan');
  assertHas_('public note', html, 'So excited!');
  assertHas_('private note', html, 'Arriving early.');
}

function testEmail_minimalPayload_() {
  Logger.log('testEmail_minimalPayload_');
  // Only required-ish fields; no party, no pizza, no role, no notes.
  var html = genEmailHTML_({ firstName: 'Grace', lastName: 'Hopper', years: '1985' });

  assertHas_('name', html, 'Grace Hopper');
  assertHas_('empty party fallback', html, '(just you, for now)');
  assertLacks_('no role line', html, 'CF Affiliation');
  assertLacks_('no pizza block', html, 'Special-order pizza');
  assertLacks_('no public note', html, 'Your public note');
  assertLacks_('no private note', html, 'Your private note');
}

function testEmail_escapesHtml_() {
  Logger.log('testEmail_escapesHtml_');
  var html = genEmailHTML_({
    firstName: '<script>', lastName: 'O\'Brien', years: '2000',
    notesPublic: 'a & b <tag>'
  });

  // User input must be escaped, not rendered as live markup.
  assertHas_('escaped name', html, '&lt;script&gt;');
  assertLacks_('no raw script tag', html, '<script>');
  assertHas_('escaped ampersand', html, 'a &amp; b &lt;tag&gt;');
}

function testEmail_regretAndEditLink_() {
  Logger.log('testEmail_regretAndEditLink_');
  // Regret email: no party/pizza details, but the edit link is present.
  var regret = genEmailHTML_(
    { firstName: 'Grace', attending: 'No', notesPublic: 'Wish I could come!' },
    'https://example.org/?edit=tok123&type=rsvp',
    false
  );
  assertHas_('regret greeting', regret, "can't make it");
  assertHas_('regret message', regret, 'Wish I could come!');
  assertHas_('edit link present', regret, 'edit=tok123');
  assertLacks_('no pizza in regret', regret, 'Special-order pizza');

  // Attending (happy-path) email also carries the edit link.
  var attending = genEmailHTML_(
    { firstName: 'Ada', attending: 'Yes', years: '1994' },
    'https://example.org/?edit=tok999&type=rsvp',
    false
  );
  assertHas_('edit link in attending email', attending, 'edit=tok999');

  // Update email uses the "updated" heading.
  var updated = genEmailHTML_({ firstName: 'Ada', attending: 'Yes', years: '1994' }, '', true);
  assertHas_('updated heading', updated, 'Your RSVP has been updated');
}

